package evaluation

import "sync/atomic"

// Metrics tracks evaluation engine metrics in a thread-safe manner.
type Metrics struct {
	total  atomic.Int64
	match  atomic.Int64
	errors atomic.Int64
}

// RecordEvaluation increments the total evaluation count.
func (m *Metrics) RecordEvaluation() {
	m.total.Add(1)
}

// RecordMatch increments the match count.
func (m *Metrics) RecordMatch() {
	m.match.Add(1)
}

// RecordError increments the error count.
func (m *Metrics) RecordError() {
	m.errors.Add(1)
}

// Total returns the total number of evaluations recorded.
func (m *Metrics) Total() int64 {
	return m.total.Load()
}

// Matches returns the total number of matches recorded.
func (m *Metrics) Matches() int64 {
	return m.match.Load()
}

// Errors returns the total number of errors recorded.
func (m *Metrics) Errors() int64 {
	return m.errors.Load()
}

// Snapshot returns a point-in-time snapshot of the metrics.
func (m *Metrics) Snapshot() MetricsSnapshot {
	return MetricsSnapshot{
		Total:  m.total.Load(),
		Matches: m.match.Load(),
		Errors: m.errors.Load(),
	}
}

// MetricsSnapshot is a point-in-time snapshot of metrics values.
type MetricsSnapshot struct {
	Total   int64
	Matches int64
	Errors  int64
}

